VALUES
  ('diplomatic-9e854390-moex-00176', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X1年初購入土地，成本$5,000,000，後續衡量採重估價模式。該土地X2年底出現減損跡 象，因而認列減損損失$500,000。若X3年底土地進行首次重估，其公允價值為$5,300,000，則關 於X3年底甲公司會計分錄，下列何者正確？', '["貸記「減損迴轉利益」$500,000", "貸記「減損迴轉利益」$800,000", "貸記「其他綜合損益－重估增值」$500,000", "貸記「其他綜合損益－重估增值」$800,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00177', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '有關投資性不動產之敘述，下列何者正確？', '["投資性不動產成本包含購買價格以及任何直接可以歸屬之支出，如法律服務費及不動產移轉之稅捐", "投資性不動產之後續衡量原則上採用公允價值模式，惟公允價值無法可靠衡量時得採成本模式", "採用公允價值模式衡量之投資性不動產，仍應計提折舊", "已採用公允價值模式衡量之投資性不動產，得從公允價值模式改變為成本模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00178', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司年初以$100,000購買一棟建築物並分類為投資性不動產。購買價款有半數是付現，剩餘價 款則開立年底到期之不附息票據$55,000（有效利率10%）支付。此外，尚支付仲介佣金$10,000及 代書費$5,000，購買此投資性不動產之成本為何？', '["$120,000", "$115,000", "$105,000", "$100,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00179', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '下列何者不屬於或有負債，但應以附註方式揭露？', '["銷項稅額", "累積特別股之積欠股利", "應付現金股利", "留抵稅額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00180', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X1年1月1日以$96,283發行2年期公司債，面額$100,000，票面利率為4%，有效利 率為6%，每年6月30日及12月31日付息，此公司債於X1年6月30日採用有效利息法和直線 法攤銷金額分別為何？（四捨五入至整數）', '["$1,777，$1,859", "$888，$929", "$1,859，$1,777", "$929，$888"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00181', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司在X1年3月1日以每股$9購回5,000股庫藏股票，6月1日以每股$12出售500股庫藏股 票，9月1日以每股$10再出售2,500股庫藏股票，12月1日以每股$6再出售1,000股庫藏股票。 若甲公司成立以來並無其他庫藏股交易，則X1年底資產負債表上庫藏股及資本公積-庫藏股之金 額分別為：', '["$9,000；$1,000", "$9,000；$1,500", "$18,000；$1,500", "$45,000；$1,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00182', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '公司處分庫藏股前，帳列資訊如次：資本公積-庫藏股交易$10,000，資本公積-普通股發行溢價 $200,000，保留盈餘$300,000。以$200,000 出售成本$240,000 之庫藏股。有關出售該庫藏股的分 錄，下列敘述何者正確？', '["借記：現金200,000；貸記：庫藏股200,000", "借記：庫藏股200,000、借記：資本公積-庫藏股交易10,000、借記：資本公積-普通股30,000； 貸記：現金240,000", "借記：現金200,000、借記：資本公積-庫藏股交易40,000；貸記：庫藏股240,000", "借記：現金200,000、借記：資本公積-庫藏股交易10,000、借記：保留盈餘30,000；貸記：庫 藏股240,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00183', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X1年1月1日有流通在外普通股400,000股，4月1日按市價現金增資100,000股，7月 1日收回庫藏股票20,000股，10月1日再售出全部庫藏股票。另外甲公司帳上有5%，累積特別 股20,000股，每股面額$100。若甲公司X1年淨利為$1,040,000，每股盈餘為多少？', '["$2", "$2.25", "$2.21", "$2.5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00184', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', 'X1年1月1日甲公司有流通在外普通股股本$2,000,000，每股面額$10，保留盈餘$5,000,000，X1 年6月1日以每股$20發行普通股80,000股，X1年12月2日宣告30%的股票股利，以每股面額 $10計算股票股利，X1年淨利為$6,000,000。X1年12月31日保留盈餘餘額為何？', '["$10,960,000", "$11,000,000", "$10,160,000", "$5,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00185', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X1年平均應收帳款為$150,000，平均存貨為$62,500，當年銷貨收入為$1,500,000，銷貨毛 利率為25%，若甲公司均以現金購貨，且一年以360天計算，則該公司營業週期為：', '["36天", "54天", "56天", "72天"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
